class Solution:
    def maxProfit(self, prices: List[int]) -> int:
        maxProfit = 0
        for i in range(len(prices) - 1):        
            j = len(prices) - 1
            while i < j:
                if prices[j] > prices[i] and prices[j] - prices[i] > maxProfit:
                    maxProfit = prices[j] - prices[i]
                j -=1
        return maxProfit

class Solution:
    def maxProfit(self, prices: List[int]) -> int:

        minimum = prices[0]
        maxProfit = 0

        for i in prices[1:]:

            if maxProfit < i - minimum:
                maxProfit = i - minimum

            if i < minimum:
                minimum = i

        return maxProfit

