class Solution:
    def isValid(self, root: Optional[TreeNode], low: int, high: int) -> bool:

        if not root:
            return True

        if not low < root.val < high:
            return False

        return self.isValid(root.left, low, root.val) and self.isValid(root.right, root.val, high)

    def isValidBST(self, root: Optional[TreeNode]) -> bool:
        return self.isValid(root, float('-inf'), float('inf'))

class Solution:
    def validPalindrome(self, s: str) -> bool:

        def isPalindrome(st: str) -> bool:

            i, j = 0, len(st) - 1

            while i < j:
                if not st[i] == st[j]: 
                    return False
                i += 1
                j -= 1
            return True

        start = 0
        end = len(s) - 1

        while start < end:
            if not s[start] == s[end]:
                return isPalindrome(s[start+1:end+1]) or isPalindrome(s[start:end])
            start += 1
            end -= 1
        return True

class Solution:
    def isValid(self, s: str) -> bool:

        stack = []
        memory = {')' : '(', ']' : '[', '}' : '{'}

        for char in s:
            if char in memory:
                if not stack:
                    return False
                if stack[-1] == memory[char]:
                    stack.pop()
                else:
                    return False
            else:
                stack.append(char)

        return len(stack) == 0
